    // --- Secure XML Parser Factory ---

    public static class SecureXmlParserFactory {

        public static DocumentBuilder createSecureDocumentBuilder() throws ParserConfigurationException {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            factory.setValidating(false);

            // Prevent XXE attacks
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            return factory.newDocumentBuilder();
        }

        public static Document parseXmlSecurely(String xmlContent) throws ParserConfigurationException, SAXException, IOException {
            DocumentBuilder builder = createSecureDocumentBuilder();
            InputSource inputSource = new InputSource(new StringReader(xmlContent));
            return builder.parse(inputSource);
        }

        public static Document parseXmlSecurely(InputStream inputStream) throws ParserConfigurationException, SAXException, IOException {
            DocumentBuilder builder = createSecureDocumentBuilder();
            return builder.parse(inputStream);
        }
    }

