    public static class XmlDocumentProcessor {

        private static final Logger LOGGER = Logger.getLogger(XmlDocumentProcessor.class.getName());

        public List<DataRecord> processDocument(Document document) {
            List<DataRecord> records = new ArrayList<>();
            Element root = document.getDocumentElement();
            LOGGER.info("Processing root element: " + root.getTagName());

            NodeList childNodes = root.getChildNodes();
            for (int i = 0; i < childNodes.getLength(); i++) {
                Node node = childNodes.item(i);
                if (node.getNodeType() == Node.ELEMENT_NODE) {
                    DataRecord record = processElement((Element) node, 0);
                    if (record != null) {
                        records.add(record);
                    }
                }
            }
            return records;
        }

        private DataRecord processElement(Element element, int depth) {
            if (depth > 50) {
                LOGGER.warning("Maximum nesting depth exceeded at element: " + element.getTagName());
                return null;
            }

            DataRecord record = new DataRecord();
            record.setEntityType(element.getTagName());

            // Process attributes of the element
            NamedNodeMap attrs = element.getAttributes();
            for (int i = 0; i < attrs.getLength(); i++) {
                Attr attr = (Attr) attrs.item(i);
                if (!attr.getName().startsWith("xmlns")) {
                    record.addAttribute("@" + attr.getName(), attr.getValue());
                }
            }

            // Check for 'id' attribute
            if (element.hasAttribute("id")) {
                record.setId(element.getAttribute("id"));
            }

            // Process child nodes
            NodeList children = element.getChildNodes();
            boolean hasChildElements = false;

            for (int i = 0; i < children.getLength(); i++) {
                Node child = children.item(i);
                if (child.getNodeType() == Node.ELEMENT_NODE) {
                    hasChildElements = true;
                    Element childElement = (Element) child;

                    // Check if this child element is a simple text element or complex
                    if (isSimpleTextElement(childElement)) {
                        String textContent = getTextContent(childElement);
                        record.addAttribute(childElement.getTagName(), textContent);
                    } else {
                        DataRecord childRecord = processElement(childElement, depth + 1);
                        if (childRecord != null) {
                            record.addChild(childRecord);
                        }
                    }
                }
            }

            // If no child elements, get text content
            if (!hasChildElements) {
                String textContent = getTextContent(element);
                if (textContent != null && !textContent.isEmpty()) {
                    record.addAttribute("_text", textContent);
                }
            }

            // Generate ID if not present
            if (record.getId() == null || record.getId().isEmpty()) {
                record.setId(UUID.randomUUID().toString());
            }

            return record;
        }

        private boolean isSimpleTextElement(Element element) {
            NodeList children = element.getChildNodes();
            for (int i = 0; i < children.getLength(); i++) {
                if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                    return false;
                }
            }
            return true;
        }

        private String getTextContent(Element element) {
            StringBuilder sb = new StringBuilder();
            NodeList children = element.getChildNodes();
            for (int i = 0; i < children.getLength(); i++) {
                Node child = children.item(i);
                if (child.getNodeType() == Node.TEXT_NODE || child.getNodeType() == Node.CDATA_SECTION_NODE) {
                    sb.append(child.getNodeValue());
                }
            }
            return sb.toString().trim();
        }
    }

    // --- Data Import Service ---

    public static class DataImportService {

        private static final Logger LOGGER = Logger.getLogger(DataImportService.class.getName());
        private final ConcurrentHashMap<String, List<DataRecord>> dataStore = new ConcurrentHashMap<>();
        private final ConcurrentHashMap<String, ImportResult> importHistory = new ConcurrentHashMap<>();

        public ImportResult importRecords(List<DataRecord> records) {
            String importId = UUID.randomUUID().toString();
            ImportResult result = new ImportResult(importId);

            LOGGER.info("Starting import " + importId + " with " + records.size() + " top-level records");

            for (DataRecord record : records) {
                try {
                    validateRecord(record);
                    storeRecord(record);
                    result.incrementSuccess();
                    LOGGER.fine("Successfully imported record: " + record.getId());
                } catch (Exception e) {
                    result.incrementFailure("Record " + record.getId() + ": " + e.getMessage());
                    LOGGER.warning("Failed to import record " + record.getId() + ": " + e.getMessage());
                }
            }

            importHistory.put(importId, result);
            LOGGER.info("Import " + importId + " completed. Success: " + result.getSuccessCount() +
                    ", Failures: " + result.getFailureCount());
            return result;
        }

        private void validateRecord(DataRecord record) throws IllegalArgumentException {
            if (record.getEntityType() == null || record.getEntityType().isEmpty()) {
                throw new IllegalArgumentException("Entity type is required");
            }
            if (record.getId() == null || record.getId().isEmpty()) {
                throw new IllegalArgumentException("Record ID is required");
            }
            // Validate children recursively
            for (DataRecord child : record.getChildren()) {
                validateRecord(child);
            }
        }

        private void storeRecord(DataRecord record) {
            dataStore.computeIfAbsent(record.getEntityType(), k -> Collections.synchronizedList(new ArrayList<>()));
            dataStore.get(record.getEntityType()).add(record);

            // Store children recursively
            for (DataRecord child : record.getChildren()) {
                storeRecord(child);
            }
        }

        public List<DataRecord> getRecordsByType(String entityType) {
            return dataStore.getOrDefault(entityType, Collections.emptyList());
        }

        public ImportResult getImportResult(String importId) {
            return importHistory.get(importId);
        }

        public Map<String, Integer> getStoreSummary() {
            Map<String, Integer> summary = new LinkedHashMap<>();
            for (Map.Entry<String, List<DataRecord>> entry : dataStore.entrySet()) {
                summary.put(entry.getKey(), entry.getValue().size());
            }
            return summary;
        }
    }

