    // --- Chunked Large Payload Processor ---

    public static class LargePayloadProcessor {

        private static final Logger LOGGER = Logger.getLogger(LargePayloadProcessor.class.getName());
        private static final int CHUNK_SIZE = 1000;

        private final DataImportService importService;
        private final XmlDocumentProcessor xmlProcessor;

        public LargePayloadProcessor(DataImportService importService) {
            this.importService = importService;
            this.xmlProcessor = new XmlDocumentProcessor();
        }

        public ImportResult processLargePayload(String xmlContent) throws Exception {
            Document document = SecureXmlParserFactory.parseXmlSecurely(xmlContent);
            Element root = document.getDocumentElement();

            List<DataRecord> allRecords = new ArrayList<>();
            NodeList children = root.getChildNodes();

            for (int i = 0; i < children.getLength(); i++) {
                Node node = children.item(i);
                if (node.getNodeType() == Node.ELEMENT_NODE) {
                    DocumentBuilder builder = SecureXmlParserFactory.createSecureDocumentBuilder();
                    Document chunkDoc = builder.newDocument();
                    Element chunkRoot = chunkDoc.createElement("Chunk");
                    chunkDoc.appendChild(chunkRoot);

                    Node imported = chunkDoc.importNode(node, true);
                    chunkRoot.appendChild(imported);

                    List<DataRecord> chunkRecords = xmlProcessor.processDocument(chunkDoc);
                    allRecords.addAll(chunkRecords);

                    // Process in chunks
                    if (allRecords.size() >= CHUNK_SIZE) {
                        LOGGER.info("Processing chunk of " + allRecords.size() + " records");
                        importService.importRecords(new ArrayList<>(allRecords));
                        allRecords.clear();
                    }
                }
            }

            // Process remaining records
            if (!allRecords.isEmpty()) {
                LOGGER.info("Processing final chunk of " + allRecords.size() + " records");
                return importService.importRecords(allRecords);
            }

            return new ImportResult(UUID.randomUUID().toString());
        }
    }

