    private static void testLargePayload(SoapMessageHandler handler) {
        StringBuilder largePayload = new StringBuilder();
        largePayload.append("<?xml version=\"1.0\" encoding=\"UTF-8\"?>");
        largePayload.append("<soap:Envelope xmlns:soap=\"http://schemas.xmlsoap.org/soap/envelope/\">");
        largePayload.append("<soap:Body>");
        largePayload.append("<ImportData xmlns=\"http://enterprise.integration/dataservice\">");
        largePayload.append("<Payload>");

        int recordCount = 100;
        for (int i = 0; i < recordCount; i++) {
            largePayload.append("<Product id=\"prod-").append(String.format("%05d", i)).append("\">");
            largePayload.append("<Name>Product ").append(i).append("</Name>");
            largePayload.append("<Category>Category-").append(i % 10).append("</Category>");
            largePayload.append("<Price>").append(10.0 + i * 1.5).append("</Price>");
            largePayload.append("<Inventory>");
            largePayload.append("<Warehouse id=\"wh-001\">");
            largePayload.append("<Quantity>").append(100 + i).append("</Quantity>");
            largePayload.append("<Location>Shelf-").append(i % 50).append("</Location>");
            largePayload.append("</Warehouse>");
            largePayload.append("<Warehouse id=\"wh-002\">");
            largePayload.append("<Quantity>").append(50 + i).append("</Quantity>");
            largePayload.append("<Location>Shelf-").append((i + 25) % 50).append("</Location>");
            largePayload.append("</Warehouse>");
            largePayload.append("</Inventory>");
            largePayload.append("<Specifications>");
            largePayload.append("<Spec name=\"weight\">").append(0.5 + i * 0.1).append("kg</Spec>");
            largePayload.append("<Spec name=\"color\">Color-").append(i % 8).append("</Spec>");
            largePayload.append("</Specifications>");
            largePayload.append("</Product>");
        }

        largePayload.append("</Payload>");
        largePayload.append("</ImportData>");
        largePayload.append("</soap:Body>");
        largePayload.append("</soap:Envelope>");

        long startTime = System.currentTimeMillis();
        String response = handler.handleSoapRequest(largePayload.toString());
        long endTime = System.currentTimeMillis();

        System.out.println("Large payload (" + recordCount + " products with nested data) processed in " +
                (endTime - startTime) + "ms");
        System.out.println("Payload size: " + (largePayload.length() / 1024) + " KB");
        System.out.println("Response:");
        System.out.println(formatXml(response));

        // Query the imported products
        String queryProducts = "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
                "<soap:Envelope xmlns:soap=\"http://schemas.xmlsoap.org/soap/envelope/\">" +
                "<soap:Body>" +
                "<GetStoreSummary xmlns=\"http://enterprise.integration/dataservice\"/>" +
                "</soap:Body>" +
                "</soap:Envelope>";

        String summaryResponse = handler.handleSoapRequest(queryProducts);
        System.out.println("\nStore Summary After Large Import:");
        System.out.println(formatXml(summaryResponse));
    }

    private static String formatXml(String xml) {
        try {
            Document doc = SecureXmlParserFactory.parseXmlSecurely(xml);
            TransformerFactory tf = TransformerFactory.newInstance();
            tf.setAttribute("indent-number", 2);
            Transformer transformer = tf.newTransformer();
            transformer.setOutputProperty(javax.xml.transform.OutputKeys.INDENT, "yes");
            transformer.setOutputProperty(javax.xml.transform.OutputKeys.OMIT_XML_DECLARATION, "yes");
            transformer.setOutputProperty("{http://xml.apache.org/xslt}indent-amount", "2");
            StringWriter writer = new StringWriter();
            transformer.transform(new DOMSource(doc), new StreamResult(writer));
            return writer.toString();
        } catch (Exception e) {
            return xml;
        }
    }
